2	
3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const LOYALTY_DISCOUNT_RATE = 0.2;
25	const LOYALTY_YEARS_THRESHOLD = 2;
26	const FOLLOWUP_DISCOUNT_RATE = 0.15;
27	const DEDUCTIBLE = 100;
28	const HIGH_ENCHANTMENT_DAMAGE_THRESHOLD = 8;
29	const HIGH_ENCHANTMENT_DAMAGE_REIMBURSEMENT_RATE = 0.5;
30	
31	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	function groupByType(items: Item[]): Map<string, Item[]> {
41	  const groups = new Map<string, Item[]>();
42	  for (const item of items) {
43	    const group = groups.get(item.type) ?? [];
44	    group.push(item);
45	    groups.set(item.type, group);
46	  }
47	  return groups;
48	}
49	
50	function premiumForGroup(type: string, group: Item[]): number {
51	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
52	    return COMPONENT_BLOCK_PREMIUM;
53	  }
54	  return group.length * BASE_PREMIUM_BY_TYPE[type];
55	}
56	
57	function isEnchantmentAtLeast(item: Item, threshold: number): boolean {
58	  return item.enchantment !== undefined && item.enchantment >= threshold;
59	}
60	
61	function modifierRateForItem(item: Item): number {
62	  let rate = 0;
63	  if (item.cursed) {
64	    rate += CURSE_SURCHARGE_RATE;
65	  }
66	  if (isEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD)) {
67	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
68	  }
69	  return rate;
70	}
71	
72	function premiumForModifiedItem(item: Item): number {
73	  const base = BASE_PREMIUM_BY_TYPE[item.type];
74	  return base + base * modifierRateForItem(item);
75	}
76	
77	function hasCursedItem(items: Item[]): boolean {
78	  return items.some((item) => item.cursed);
79	}
80	
81	function hasHighEnchantmentItem(items: Item[]): boolean {
82	  return items.some((item) => isEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD));
83	}
84	
85	function hasItemModifier(items: Item[]): boolean {
86	  return hasCursedItem(items) || hasHighEnchantmentItem(items);
87	}
88	
89	function baseTotalForItems(items: Item[]): number {
90	  return items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
91	}
92	
93	function premiumForItems(items: Item[]): number {
94	  if (hasItemModifier(items)) {
95	    return items.reduce((sum, item) => sum + premiumForModifiedItem(item), 0);
96	  }
97	  return Array.from(groupByType(items)).reduce(
98	    (sum, [type, group]) => sum + premiumForGroup(type, group),
99	    0,
100	  );
101	}
102	
103	function qualifiesForFirstInsuranceSurcharge(input: QuoteInput): boolean {
104	  return input.items.length === 1 && hasItemModifier(input.items);
105	}
106	
107	function qualifiesForLoyaltyDiscount(input: QuoteInput): boolean {
108	  return input.customerYears >= LOYALTY_YEARS_THRESHOLD;
109	}
110	
111	function qualifiesForFollowupDiscount(input: QuoteInput): boolean {
112	  return input.previousContracts >= 1;
113	}
114	
115	export type Damage = {
116	  itemType: string;
117	  amount: number;
118	};
119	
120	export type ClaimInput = {
121	  items: Item[];
122	  remainingCap: number;
123	  damages: Damage[];
124	};
125	
126	export type ClaimResult = {
127	  payout: number;
128	  remainingCap: number;
129	};
130	
131	function payoutForDamage(damage: Damage, items: Item[]): number {
132	  const item = items.find((i) => i.type === damage.itemType);
133	  const isHighEnchantmentDamage =
134	    item !== undefined && isEnchantmentAtLeast(item, HIGH_ENCHANTMENT_DAMAGE_THRESHOLD);
135	  const reimbursement = isHighEnchantmentDamage
136	    ? damage.amount * HIGH_ENCHANTMENT_DAMAGE_REIMBURSEMENT_RATE
137	    : damage.amount;
138	  return reimbursement - DEDUCTIBLE;
139	}
140	
141	export function claim(input: ClaimInput): ClaimResult {
142	  const payout = input.damages.reduce(
143	    (sum, damage) => sum + payoutForDamage(damage, input.items),
144	    0,
145	  );
146	  return { payout, remainingCap: input.remainingCap };
147	}
148	
149	export function quote(input: QuoteInput): number {
150	  let premium = premiumForItems(input.items);
151	  const baseTotal = baseTotalForItems(input.items);
152	  if (qualifiesForFirstInsuranceSurcharge(input)) {
153	    premium += baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
154	  }
155	  if (qualifiesForLoyaltyDiscount(input)) {
156	    premium -= baseTotal * LOYALTY_DISCOUNT_RATE;
157	  }
158	  if (qualifiesForFollowupDiscount(input)) {
159	    premium -= baseTotal * FOLLOWUP_DISCOUNT_RATE;
160	  }
161	  return Math.ceil(premium + PROCESSING_FEE);
162	}
